CREATE TABLE IF NOT EXISTS indicators (id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, indicator_type VARCHAR(30) NOT NULL, value VARCHAR(512) NOT NULL, confidence_score DOUBLE PRECISION NOT NULL CHECK (confidence_score BETWEEN 0 AND 100), reputation_score DOUBLE PRECISION CHECK (reputation_score BETWEEN 0 AND 100), threat_category VARCHAR(100) NOT NULL, country VARCHAR(2), status VARCHAR(30) NOT NULL, first_seen_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, last_seen_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE(indicator_type,value));
